 5→//! JJK chalk command - empty commits marking steeplechase events
 6→//!
 7→//! The chalk command creates empty commits with special formatting for tracking
 8→//! steeplechase events like approach, wrap, fly, or heat-level discussions.
 9→
10→use vvc::{vvco_out, vvco_err, vvco_Output};
11→
12→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark};
13→use crate::jjrn_notch::{jjrn_ChalkMarker as ChalkMarker, jjrn_format_chalk_message, jjrn_format_heat_discussion};
14→
15→/// Arguments for jjx_chalk command
16→#[derive(clap::Args, Debug)]
17→pub struct jjrx_ChalkArgs {
18→    /// Identity: Coronet (pace-level) or Firemark (heat-level discussion only)
19→    pub identity: String,
20→
21→    /// Marker type: A(pproach), W(rap), F(ly), d(iscussion)
22→    #[arg(long)]
23→    pub marker: String,
24→
25→    /// Marker description text
26→    #[arg(long)]
27→    pub description: String,
28→}
29→
30→/// Run the chalk command - create steeplechase marker commit
31→pub fn jjrx_run_chalk(args: jjrx_ChalkArgs) -> (i32, String) {
32→    let mut output = vvco_Output::buffer();
33→
34→    let marker = match ChalkMarker::jjrn_parse(&args.marker) {
35→        Ok(m) => m,
36→        Err(e) => {
37→            vvco_err!(output, "jjx_chalk: error: {}", e);
38→            return (1, output.vvco_finish());
39→        }
40→    };
41→
42→    // Try parsing as Coronet first (5 base64 chars), then as Firemark (2 base64 chars)
43→    let identity = args.identity.strip_prefix('₢').or_else(|| args.identity.strip_prefix('₣')).unwrap_or(&args.identity);
44→
45→    let message = if identity.len() == 5 {
46→        // Coronet - pace-level chalk
47→        let coronet = match Coronet::jjrf_parse(&args.identity) {
48→            Ok(c) => c,
49→            Err(e) => {
50→                vvco_err!(output, "jjx_chalk: error: {}", e);
51→                return (1, output.vvco_finish());
52→            }
53→        };
54→        jjrn_format_chalk_message(&coronet, marker, &args.description)
55→    } else if identity.len() == 2 {
56→        // Firemark - heat-level (discussion, session)
57→        if marker.jjrn_requires_pace() {
58→            vvco_err!(output, "jjx_chalk: error: {} marker requires a Coronet (pace identity), not a Firemark", marker.jjrn_as_str());
59→            return (1, output.vvco_finish());
60→        }
61→        let firemark = match Firemark::jjrf_parse(&args.identity) {
62→            Ok(fm) => fm,
63→            Err(e) => {
64→                vvco_err!(output, "jjx_chalk: error: {}", e);
65→                return (1, output.vvco_finish());
66→            }
67→        };
68→
69→        jjrn_format_heat_discussion(&firemark, &args.description)
70→    } else {
71→        vvco_err!(output, "jjx_chalk: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
72→        return (1, output.vvco_finish());
73→    };
74→
75→    let commit_args = vvc::vvcc_CommitArgs {
76→        prefix: None,
77→        message: Some(message),
78→        allow_empty: true,
79→        no_stage: true,
80→        size_limit: vvc::VVCG_SIZE_LIMIT,
81→        warn_limit: vvc::VVCG_WARN_LIMIT,
82→    };
83→
84→    let rc = vvc::commit(&commit_args, &mut output);
85→    (rc, output.vvco_finish())
86→}
