  5→//! JJK Tally commands - pace modification operations
  6→//!
  7→//! Split into four single-purpose commands:
  8→//! - revise_docket: Update pace docket text
  9→//! - arm: Set state to bridled with warrant
 10→//! - relabel: Rename pace silks
 11→//! - drop: Set state to abandoned
 12→
 13→use std::path::PathBuf;
 14→
 15→use vvc::{vvco_out, vvco_err, vvco_Output};
 16→
 17→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 18→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
 19→use crate::jjrn_notch::{jjrn_format_heat_message as format_heat_message, jjrn_HeatAction as HeatAction};
 20→
 21→/// Arguments for jjx_revise_docket command
 22→#[derive(clap::Args, Debug)]
 23→pub struct jjrtl_ReviseDocketArgs {
 24→    /// Path to the Gallops JSON file
 25→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 26→    pub file: PathBuf,
 27→
 28→    /// Target Pace identity (Coronet)
 29→    pub coronet: String,
 30→}
 31→
 32→/// Run the revise_docket command
 33→///
 34→/// Updates the docket text for a pace.
 35→pub fn jjrtl_run_revise_docket(args: jjrtl_ReviseDocketArgs, docket: String) -> (i32, String) {
 36→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
 37→    let mut output = vvco_Output::buffer();
 38→
 39→    // Acquire lock FIRST - fail fast if another operation is in progress
 40→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 41→        Ok(l) => l,
 42→        Err(e) => {
 43→            vvco_err!(output, "jjx_revise_docket: error: {}", e);
 44→            return (1, output.vvco_finish());
 45→        }
 46→    };
 47→
 48→    let text = docket;
 49→
 50→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 51→        Ok(g) => g,
 52→        Err(e) => {
 53→            vvco_err!(output, "jjx_revise_docket: error loading Gallops: {}", e);
 54→            return (1, output.vvco_finish());
 55→        }
 56→    };
 57→
 58→    // Get firemark and silks for commit message before we move args
 59→    let coronet_str = args.coronet.clone();
 60→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
 61→        Ok(c) => {
 62→            let parent_fm = c.jjrf_parent_firemark();
 63→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
 64→                .and_then(|h| h.paces.get(&c.jjrf_display()))
 65→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
 66→                .unwrap_or_else(|| coronet_str.clone());
 67→            (parent_fm, silks)
 68→        }
 69→        Err(e) => {
 70→            vvco_err!(output, "jjx_revise_docket: error: {}", e);
 71→            return (1, output.vvco_finish());
 72→        }
 73→    };
 74→
 75→    let tally_args = LibTallyArgs {
 76→        coronet: args.coronet,
 77→        state: None,
 78→        direction: None,
 79→        text: Some(text),
 80→        silks: None,
 81→    };
 82→
 83→    match gallops.jjrg_tally(tally_args) {
 84→        Ok(()) => {
 85→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
 86→
 87→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000, &mut output) {
 88→                Ok(hash) => {
 89→                    vvco_out!(output, "committed {}", hash);
 90→                    (0, output.vvco_finish())
 91→                }
 92→                Err(e) => {
 93→                    vvco_err!(output, "jjx_revise_docket: error: {}", e);
 94→                    (1, output.vvco_finish())
 95→                }
 96→            }
 97→        }
 98→        Err(e) => {
 99→            vvco_err!(output, "jjx_revise_docket: error: {}", e);
100→            (1, output.vvco_finish())
101→        }
102→    }
103→    // lock released here
104→}
