106→/// Arguments for jjx_arm command
107→#[derive(clap::Args, Debug)]
108→pub struct jjrtl_ArmArgs {
109→    /// Path to the Gallops JSON file
110→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
111→    pub file: PathBuf,
112→
113→    /// Target Pace identity (Coronet)
114→    pub coronet: String,
115→}
