117→/// Run the arm command
118→///
119→/// Sets pace state to bridled with warrant.
120→/// Creates both a tally commit and a B commit.
121→pub fn jjrtl_run_arm(args: jjrtl_ArmArgs, warrant: String) -> (i32, String) {
122→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
123→    let mut output = vvco_Output::buffer();
124→
125→    // Acquire lock FIRST - fail fast if another operation is in progress
126→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
127→        Ok(l) => l,
128→        Err(e) => {
129→            vvco_err!(output, "jjx_arm: error: {}", e);
130→            return (1, output.vvco_finish());
131→        }
132→    };
133→
134→    let mut gallops = match Gallops::jjrg_load(&args.file) {
135→        Ok(g) => g,
136→        Err(e) => {
137→            vvco_err!(output, "jjx_arm: error loading Gallops: {}", e);
138→            return (1, output.vvco_finish());
139→        }
140→    };
141→
142→    // Get firemark and silks for commit message before we move args
143→    let coronet_str = args.coronet.clone();
144→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
145→        Ok(c) => {
146→            let parent_fm = c.jjrf_parent_firemark();
147→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
148→                .and_then(|h| h.paces.get(&c.jjrf_display()))
149→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
150→                .unwrap_or_else(|| coronet_str.clone());
151→            (parent_fm, silks)
152→        }
153→        Err(e) => {
154→            vvco_err!(output, "jjx_arm: error: {}", e);
155→            return (1, output.vvco_finish());
156→        }
157→    };
158→
159→    let tally_args = LibTallyArgs {
160→        coronet: args.coronet,
161→        state: Some(PaceState::Bridled),
162→        direction: Some(warrant.clone()),
163→        text: None,
164→        silks: None,
165→    };
166→
167→    match gallops.jjrg_tally(tally_args) {
168→        Ok(()) => {
169→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
170→
171→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000, &mut output) {
172→                Ok(hash) => {
173→                    vvco_out!(output, "committed {}", hash);
174→                }
175→                Err(e) => {
176→                    vvco_err!(output, "jjx_arm: error: {}", e);
177→                    return (1, output.vvco_finish());
178→                }
179→            }
180→
181→            // Create B commit for bridling
182→            let coronet = match Coronet::jjrf_parse(&coronet_str) {
183→                Ok(c) => c,
184→                Err(e) => {
185→                    vvco_err!(output, "jjx_arm: error parsing coronet for B commit: {}", e);
186→                    return (1, output.vvco_finish());
187→                }
188→            };
189→
190→            let agent = "arm"; // Agent that bridled the pace
191→
192→            // Build B commit message
193→            use crate::jjrn_notch::jjrn_format_bridle_message;
194→            let b_subject = jjrn_format_bridle_message(&coronet, agent, &silks);
195→            let b_message = format!("{}\n\n{}", b_subject, warrant);
196→
197→            // Create empty B commit using git directly (like chalk markers)
198→            let git_result = vvc::vvce_git_command(&["commit", "--allow-empty", "-m", &b_message])
199→                .output();
200→
201→            match git_result {
202→                Ok(result) if result.status.success() => {
203→                    // Get commit hash
204→                    let hash_output = vvc::vvce_git_command(&["rev-parse", "HEAD"])
205→                        .output();
206→
207→                    if let Ok(hash_result) = hash_output {
208→                        if hash_result.status.success() {
209→                            let hash = String::from_utf8_lossy(&hash_result.stdout).trim().to_string();
210→                            vvco_out!(output, "B commit {}", &hash[..8.min(hash.len())]);
211→                        }
212→                    }
213→                }
214→                Ok(result) => {
215→                    let stderr = String::from_utf8_lossy(&result.stderr);
216→                    vvco_err!(output, "jjx_arm: error creating B commit: {}", stderr);
217→                    return (1, output.vvco_finish());
218→                }
219→                Err(e) => {
220→                    vvco_err!(output, "jjx_arm: error creating B commit: {}", e);
221→                    return (1, output.vvco_finish());
222→                }
223→            }
224→
225→            vvco_out!(output, "");
226→            vvco_out!(output, "Recommended: mount {} to execute", fm.jjrf_as_str());
227→            (0, output.vvco_finish())
228→        }
229→        Err(e) => {
230→            vvco_err!(output, "jjx_arm: error: {}", e);
231→            (1, output.vvco_finish())
232→        }
233→    }
234→    // lock released here
235→}
