252→/// Run the relabel command
253→///
254→/// Renames the pace silks.
255→pub fn jjrtl_run_relabel(args: jjrtl_RelabelArgs) -> (i32, String) {
256→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
257→    let mut output = vvco_Output::buffer();
258→
259→    // Acquire lock FIRST - fail fast if another operation is in progress
260→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
261→        Ok(l) => l,
262→        Err(e) => {
263→            vvco_err!(output, "jjx_relabel: error: {}", e);
264→            return (1, output.vvco_finish());
265→        }
266→    };
267→
268→    let mut gallops = match Gallops::jjrg_load(&args.file) {
269→        Ok(g) => g,
270→        Err(e) => {
271→            vvco_err!(output, "jjx_relabel: error loading Gallops: {}", e);
272→            return (1, output.vvco_finish());
273→        }
274→    };
275→
276→    // Get firemark for commit message before we move args
277→    let coronet_str = args.coronet.clone();
278→    let new_silks = args.silks.clone();
279→    let fm = match Coronet::jjrf_parse(&coronet_str) {
280→        Ok(c) => c.jjrf_parent_firemark(),
281→        Err(e) => {
282→            vvco_err!(output, "jjx_relabel: error: {}", e);
283→            return (1, output.vvco_finish());
284→        }
285→    };
286→
287→    let tally_args = LibTallyArgs {
288→        coronet: args.coronet,
289→        state: None,
290→        direction: None,
291→        text: None,
292→        silks: Some(args.silks),
293→    };
294→
295→    match gallops.jjrg_tally(tally_args) {
296→        Ok(()) => {
297→            let message = format_heat_message(&fm, HeatAction::Tally, &new_silks);
298→
299→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000, &mut output) {
300→                Ok(hash) => {
301→                    vvco_out!(output, "committed {}", hash);
302→                    (0, output.vvco_finish())
303→                }
304→                Err(e) => {
305→                    vvco_err!(output, "jjx_relabel: error: {}", e);
306→                    (1, output.vvco_finish())
307→                }
308→            }
309→        }
310→        Err(e) => {
311→            vvco_err!(output, "jjx_relabel: error: {}", e);
312→            (1, output.vvco_finish())
313→        }
314→    }
315→    // lock released here
316→}
