152→/// Format the chalk message: jjb:HALLMARK:₢CORONET:X: description
153→///
154→/// Returns the full commit message for a chalk (steeplechase marker) commit.
155→pub fn jjrn_format_chalk_message(coronet: &Coronet, marker: jjrn_ChalkMarker, description: &str) -> String {
156→    let hallmark = vvc::vvcc_get_hallmark();
157→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
158→    let action = marker.jjrn_code().to_string();
159→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action, description, None)
160→}
161→
162→/// Format a heat-level discussion message (no pace context): jjb:HALLMARK:₣XX:d: description
163→pub fn jjrn_format_heat_discussion(firemark: &Firemark, description: &str) -> String {
164→    let hallmark = vvc::vvcc_get_hallmark();
165→    let identity = format!("{}{}", FIREMARK_PREFIX, firemark.jjrf_as_str());
166→    let action = JJRNM_DISCUSSION.to_string();
167→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action, description, None)
168→}
169→
170→/// Format a heat-level action message: jjb:HALLMARK:₣XX:X: description
171→///
172→/// Used for nominate, slate, rail, tally, draft, retire operations.
173→pub fn jjrn_format_heat_message(firemark: &Firemark, action: jjrn_HeatAction, description: &str) -> String {
174→    let hallmark = vvc::vvcc_get_hallmark();
175→    let identity = format!("{}{}", FIREMARK_PREFIX, firemark.jjrf_as_str());
176→    let action_code = action.jjrn_code().to_string();
177→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action_code, description, None)
178→}
179→
180→/// Format a bridle message: jjb:HALLMARK:₢CORONET:B: {agent} | {silks}
181→///
182→/// Creates the subject line for a B (bridle) commit.
183→/// Body should contain the full direction text.
184→pub fn jjrn_format_bridle_message(coronet: &Coronet, agent: &str, silks: &str) -> String {
185→    let hallmark = vvc::vvcc_get_hallmark();
186→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
187→    let subject = format!("{} | {}", agent, silks);
188→    let action = JJRNM_BRIDLE.to_string();
189→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action, &subject, None)
190→}
191→
192→/// Format a landing message: jjb:HALLMARK:₢CORONET:L: {agent} landed
193→///
194→/// Creates the subject line for an L (landing) commit.
195→/// Body should contain the agent completion report.
196→pub fn jjrn_format_landing_message(coronet: &Coronet, agent: &str) -> String {
197→    let hallmark = vvc::vvcc_get_hallmark();
198→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
199→    let subject = format!("{} landed", agent);
200→    let action = JJRNM_LANDING.to_string();
201→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action, &subject, None)
202→}
