273→#[tool_router]
274→impl jjrm_McpServer {
275→    pub fn jjrm_new() -> Self {
276→        Self {
277→            tool_router: Self::tool_router(),
278→        }
279→    }
280→
281→    #[tool(name = "jjx", description = "Job Jockey Kit - MCP tools for project initiative management")]
282→    async fn jjx(&self, Parameters(p): Parameters<jjrm_JjxParams>) -> Result<CallToolResult, McpError> {
283→        let cmd = p.command.as_str();
284→        let v = match p.params {
285→            serde_json::Value::String(ref s) => {
286→                serde_json::from_str(s).unwrap_or(p.params)
287→            }
288→            other => other,
289→        };
290→
291→        macro_rules! deser {
292→            ($t:ty) => {
293→                match serde_json::from_value::<$t>(v) {
294→                    Ok(p) => p,
295→                    Err(e) => return jjrm_deser_error(cmd, e),
296→                }
297→            }
298→        }
299→
300→        match cmd {
301→            "jjx_record" => {
302→                let p = deser!(jjrm_RecordParams);
303→                jjrm_result(jjrnc_run_notch(jjrnc_NotchArgs {
304→                    identity: p.identity,
305→                    files: p.files,
306→                    size_limit: p.size_limit,
307→                    intent: p.intent,
308→                }))
309→            }
310→            "jjx_mark" => {
311→                let p = deser!(jjrm_MarkParams);
312→                jjrm_result(jjrx_run_chalk(jjrx_ChalkArgs {
313→                    identity: p.identity,
314→                    marker: p.marker,
315→                    description: p.description,
316→                }))
317→            }
318→            "jjx_log" => {
319→                let p = deser!(jjrm_LogParams);
320→                jjrm_result(jjrrn_run_rein(jjrrn_ReinArgs {
321→                    firemark: p.firemark,
322→                    limit: p.limit.unwrap_or(50),
323→                }))
324→            }
325→            "jjx_validate" => {
326→                let _p = deser!(jjrm_ValidateParams);
327→                jjrm_result(jjrvl_run_validate(jjrvl_ValidateArgs {
328→                    file: gallops_pathbuf(),
329→                }))
330→            }
331→            "jjx_list" => {
332→                let p = deser!(jjrm_ListParams);
333→                jjrm_result(jjrmu_run_muster(jjrmu_MusterArgs {
334→                    file: gallops_pathbuf(),
335→                    status: p.status,
336→                }).await)
337→            }
338→            "jjx_orient" => {
339→                let p = deser!(jjrm_OrientParams);
340→                jjrm_result(jjrsd_run_saddle(jjrsd_SaddleArgs {
341→                    file: gallops_pathbuf(),
342→                    firemark: p.firemark,
343→                }).await)
344→            }
345→            "jjx_show" => {
346→                let p = deser!(jjrm_ShowParams);
347→                jjrm_result(jjrpd_run_parade(jjrpd_ParadeArgs {
348→                    file: gallops_pathbuf(),
349→                    target: p.target,
350→                    detail: p.detail,
351→                    remaining: p.remaining,
352→                }))
353→            }
354→            "jjx_archive" => {
355→                let p = deser!(jjrm_ArchiveParams);
356→                jjrm_result(jjrrt_run_retire(jjrrt_RetireArgs {
357→                    file: gallops_pathbuf(),
358→                    firemark: p.firemark,
359→                    size_limit: p.size_limit,
360→                }))
361→            }
362→            "jjx_create" => {
363→                let p = deser!(jjrm_CreateParams);
364→                jjrm_result(jjrx_run_nominate(jjrx_NominateArgs {
365→                    file: gallops_pathbuf(),
366→                    silks: p.silks,
367→                }))
368→            }
369→            "jjx_enroll" => {
370→                let p = deser!(jjrm_EnrollParams);
371→                jjrm_result(jjrsl_run_slate(jjrsl_SlateArgs {
372→                    file: gallops_pathbuf(),
373→                    firemark: p.firemark,
374→                    silks: p.silks,
375→                    before: p.before,
376→                    after: p.after,
377→                    first: p.first,
378→                }, p.docket))
379→            }
380→            "jjx_reorder" => {
381→                let p = deser!(jjrm_ReorderParams);
382→                jjrm_result(jjrrl_run_rail(jjrrl_RailArgs {
383→                    file: gallops_pathbuf(),
384→                    firemark: p.firemark,
385→                    order: vec![],
386→                    r#move: p.r#move,
387→                    before: p.before,
388→                    after: p.after,
389→                    first: p.first,
390→                    last: p.last,
391→                }))
392→            }
393→            "jjx_revise_docket" => {
394→                let p = deser!(jjrm_ReviseDocketParams);
395→                jjrm_result(jjrtl_run_revise_docket(jjrtl_ReviseDocketArgs {
396→                    file: gallops_pathbuf(),
397→                    coronet: p.coronet,
398→                }, p.docket))
399→            }
400→            "jjx_arm" => {
401→                let p = deser!(jjrm_ArmParams);
402→                jjrm_result(jjrtl_run_arm(jjrtl_ArmArgs {
403→                    file: gallops_pathbuf(),
404→                    coronet: p.coronet,
405→                }, p.warrant))
406→            }
407→            "jjx_relabel" => {
408→                let p = deser!(jjrm_RelabelParams);
409→                jjrm_result(jjrtl_run_relabel(jjrtl_RelabelArgs {
410→                    file: gallops_pathbuf(),
411→                    coronet: p.coronet,
412→                    silks: p.silks,
413→                }))
414→            }
415→            "jjx_drop" => {
416→                let p = deser!(jjrm_DropParams);
417→                jjrm_result(jjrtl_run_drop(jjrtl_DropArgs {
418→                    file: gallops_pathbuf(),
419→                    coronet: p.coronet,
420→                }))
421→            }
422→            "jjx_relocate" => {
423→                let p = deser!(jjrm_RelocateParams);
424→                jjrm_result(jjrdr_run_draft(jjrdr_DraftArgs {
425→                    file: gallops_pathbuf(),
426→                    coronet: p.coronet,
427→                    to: p.to,
428→                    before: p.before,
429→                    after: p.after,
430→                    first: p.first,
431→                }))
432→            }
433→            "jjx_alter" => {
434→                let p = deser!(jjrm_AlterParams);
435→                jjrm_result(jjrfu_run_furlough(jjrfu_FurloughArgs {
436→                    file: gallops_pathbuf(),
437→                    firemark: p.firemark,
438→                    racing: p.racing,
439→                    stabled: p.stabled,
440→                    silks: p.silks,
441→                }))
442→            }
443→            "jjx_close" => {
444→                let p = deser!(jjrm_CloseParams);
445→                jjrm_result(zjjrx_run_wrap(jjrx_WrapArgs {
446→                    coronet: p.coronet,
447→                    size_limit: p.size_limit,
448→                }, p.summary))
449→            }
450→            "jjx_search" => {
451→                let p = deser!(jjrm_SearchParams);
452→                jjrm_result(jjrsc_run_scout(jjrsc_ScoutArgs {
453→                    file: gallops_pathbuf(),
454→                    pattern: p.pattern,
455→                    actionable: p.actionable,
456→                }))
457→            }
458→            "jjx_get_brief" => {
459→                let p = deser!(jjrm_GetBriefParams);
460→                jjrm_result(jjrgs_run_get_spec(jjrgs_GetSpecArgs {
461→                    file: gallops_pathbuf(),
462→                    coronet: p.coronet,
463→                }))
464→            }
465→            "jjx_get_coronets" => {
466→                let p = deser!(jjrm_GetCoronetsParams);
467→                jjrm_result(jjrgc_run_get_coronets(jjrgc_GetCoronetsArgs {
468→                    file: gallops_pathbuf(),
469→                    firemark: p.firemark,
470→                    remaining: p.remaining,
471→                    rough: p.rough,
472→                }))
473→            }
474→            "jjx_paddock" => {
475→                let p = deser!(jjrm_PaddockParams);
476→                jjrm_result(jjrcu_run_curry(jjrcu_CurryArgs {
477→                    file: gallops_pathbuf(),
478→                    firemark: p.firemark,
479→                    note: p.note,
480→                }, p.content))
481→            }
482→            "jjx_continue" => {
483→                let p = deser!(jjrm_ContinueParams);
484→                jjrm_result(jjrgl_run_garland(jjrgl_GarlandArgs {
485→                    file: gallops_pathbuf(),
486→                    firemark: p.firemark,
487→                }))
488→            }
489→            "jjx_transfer" => {
490→                let p = deser!(jjrm_TransferParams);
491→                jjrm_result(jjrrs_run(jjrrs_RestringArgs {
492→                    file: gallops_pathbuf(),
493→                    firemark: p.firemark,
494→                    to: p.to,
495→                }, p.coronets))
496→            }
497→            "jjx_landing" => {
498→                let p = deser!(jjrm_LandingParams);
499→                jjrm_result(jjrld_run_landing(jjrld_LandingArgs {
500→                    coronet: p.coronet,
501→                    agent: p.agent,
502→                }, p.content.unwrap_or_default()))
503→            }
504→            _ => {
505→                Ok(CallToolResult::error(vec![Content::text(format!("jjx: unknown command '{}'\nAvailable: jjx_list, jjx_show, jjx_orient, jjx_record, jjx_mark, jjx_log, jjx_validate, jjx_create, jjx_enroll, jjx_close, jjx_archive, jjx_reorder, jjx_revise_docket, jjx_arm, jjx_relabel, jjx_drop, jjx_relocate, jjx_alter, jjx_search, jjx_get_brief, jjx_get_coronets, jjx_paddock, jjx_continue, jjx_transfer, jjx_landing", cmd))]))
506→            }
