528→    use rmcp::ServiceExt;
529→
530→    let server = jjrm_McpServer::jjrm_new();
531→    let service = server
532→        .serve(rmcp::transport::stdio())
533→        .await
534→        .map_err(|e| format!("MCP serve error: {}", e))?;
535→
536→    service.waiting().await?;
537→    Ok(())
538→}
