  5→//! Gallops utility functions
  6→//!
  7→//! Helper functions for seed management, commit capture, and I/O.
  8→
  9→use std::io::Read as IoRead;
 10→use crate::jjrc_core::jjrc_timestamp_full as timestamp_full;
 11→use crate::jjrf_favor::JJRF_CHARSET;
 12→use crate::jjrt_types::*;
 13→
 14→/// Increment a base64 seed string (with carry)
 15→/// Works for both 2-char (heat) and 3-char (pace) seeds
 16→#[allow(dead_code)]
 17→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
 18→    let mut chars: Vec<u8> = seed.bytes().collect();
 19→    let mut carry = true;
 20→
 21→    // Process from right to left
 22→    for i in (0..chars.len()).rev() {
 23→        if !carry {
 24→            break;
 25→        }
 26→
 27→        // Find current position in charset
 28→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
 29→
 30→        if pos == 63 {
 31→            // Wrap around
 32→            chars[i] = JJRF_CHARSET[0];
 33→            // carry remains true
 34→        } else {
 35→            chars[i] = JJRF_CHARSET[pos + 1];
 36→            carry = false;
 37→        }
 38→    }
 39→
 40→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
 41→}
 42→
 43→/// Capture current commit SHA for basis field
 44→///
 45→/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_BASIS length.
 46→/// Returns JJRG_UNKNOWN_BASIS on error (e.g., not in a git repo).
 47→pub fn jjrg_capture_commit_sha() -> String {
 48→    let short_arg = format!("--short={}", JJRG_UNKNOWN_BASIS.len());
 49→    match vvc::vvce_git_command(&["rev-parse", &short_arg, "HEAD"])
 50→        .output()
 51→    {
 52→        Ok(output) if output.status.success() => {
 53→            String::from_utf8_lossy(&output.stdout).trim().to_string()
 54→        }
 55→        _ => JJRG_UNKNOWN_BASIS.to_string(),
 56→    }
 57→}
 58→
 59→/// Create a new Tack with current timestamp and basis SHA
 60→///
 61→/// Centralizes Tack creation to ensure consistent timestamp/basis capture.
 62→/// All code creating new Tacks should use this helper.
 63→pub fn jjrg_make_tack(
 64→    state: jjrg_PaceState,
 65→    text: String,
 66→    silks: String,
 67→    direction: Option<String>,
 68→) -> jjrg_Tack {
 69→    jjrg_Tack {
 70→        ts: timestamp_full(),
 71→        state,
 72→        text,
 73→        silks,
 74→        basis: jjrg_capture_commit_sha(),
 75→        direction,
 76→    }
 77→}
 78→
 79→/// Read text from stdin (for CLI commands)
 80→pub fn jjrg_read_stdin() -> Result<String, String> {
 81→    let mut buffer = String::new();
 82→    std::io::stdin().read_to_string(&mut buffer)
 83→        .map_err(|e| format!("Failed to read from stdin: {}", e))?;
 84→    Ok(buffer.trim_end().to_string())
 85→}
 86→
 87→/// Read text from stdin, returning None if stdin is empty or a tty
 88→pub fn jjrg_read_stdin_optional() -> Result<Option<String>, String> {
 89→    use std::io::IsTerminal;
 90→
 91→    // If stdin is a terminal, no input was piped
 92→    if std::io::stdin().is_terminal() {
 93→        return Ok(None);
 94→    }
 95→
 96→    let text = jjrg_read_stdin()?;
 97→    if text.is_empty() {
 98→        Ok(None)
 99→    } else {
100→        Ok(Some(text))
101→    }
102→}
