 20→/// Nominate a new Heat
 21→///
 22→/// Creates a new Heat with empty Pace structure and creates the paddock file.
 23→pub fn jjrg_nominate(gallops: &mut jjrg_Gallops, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
 24→    // Validate silks is alphanumeric-kebab
 25→    if !zjjrg_is_kebab_case(&args.silks) {
 26→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
 27→    }
 28→
 29→    // Validate created is YYMMDD
 30→    if !zjjrg_is_yymmdd(&args.created) {
 31→        return Err(format!("created must be YYMMDD format, got '{}'", args.created));
 32→    }
 33→
 34→    // Allocate Firemark from next_heat_seed
 35→    let firemark_str = format!("{}{}", FIREMARK_PREFIX, gallops.next_heat_seed);
 36→    let heat_id = gallops.next_heat_seed.clone();
 37→
 38→    // Compute paddock path
 39→    let paddock_file = jjri_paddock_path(&heat_id);
 40→
 41→    // Create paddock file with template
 42→    let paddock_path = base_path.join(&paddock_file);
 43→    if let Some(parent) = paddock_path.parent() {
 44→        fs::create_dir_all(parent)
 45→            .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
 46→    }
 47→
 48→    let paddock_content = format!(
 49→        "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
 50→        args.silks
 51→    );
 52→
 53→    fs::write(&paddock_path, paddock_content)
 54→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
 55→
 56→    // Create new Heat
 57→    let heat = jjrg_Heat {
 58→        silks: args.silks,
 59→        creation_time: args.created,
 60→        status: jjrg_HeatStatus::Stabled,
 61→        order: Vec::new(),
 62→        next_pace_seed: "AAA".to_string(),
 63→        paddock_file,
 64→        paces: BTreeMap::new(),
 65→    };
 66→
 67→    // Insert Heat
 68→    gallops.heats.insert(firemark_str.clone(), heat);
 69→    gallops.heat_order.push(firemark_str.clone());
 70→
 71→    // Increment next_heat_seed
 72→    gallops.next_heat_seed = zjjrg_increment_seed(&gallops.next_heat_seed);
 73→
 74→    Ok(jjrg_NominateResult { firemark: firemark_str })
 75→}
 76→
 77→/// Slate a new Pace
 78→///
 79→/// Adds a new Pace to a Heat with an initial Tack in rough state.
 80→/// Positioning: use before/after/first to insert at specific location.
 81→pub fn jjrg_slate(gallops: &mut jjrg_Gallops, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
 82→    // Validate silks is alphanumeric-kebab
 83→    if !zjjrg_is_kebab_case(&args.silks) {
 84→        return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", args.silks));
 85→    }
 86→
 87→    // Validate text is non-empty
 88→    if args.text.is_empty() {
 89→        return Err("text must not be empty".to_string());
 90→    }
 91→
 92→    // Validate positioning mutual exclusivity
 93→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
 94→        .iter()
 95→        .filter(|&&x| x)
 96→        .count();
 97→    if position_count > 1 {
 98→        return Err("Only one of --before, --after, or --first may be specified".to_string());
 99→    }
100→
101→    // Parse and normalize firemark
102→    let firemark = Firemark::jjrf_parse(&args.firemark)
103→        .map_err(|e| format!("Invalid firemark: {}", e))?;
104→    let firemark_key = firemark.jjrf_display();
105→
106→    // Verify Heat exists
107→    let heat = gallops.heats.get_mut(&firemark_key)
108→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
109→
110→    // If --before or --after specified, validate target coronet exists
111→    let insert_position = if let Some(ref before_str) = args.before {
112→        let target = Coronet::jjrf_parse(before_str)
113→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
114→        let target_key = target.jjrf_display();
115→        let pos = heat.order.iter().position(|c| c == &target_key)
116→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
117→        Some(pos) // Insert before this position
118→    } else if let Some(ref after_str) = args.after {
119→        let target = Coronet::jjrf_parse(after_str)
120→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
121→        let target_key = target.jjrf_display();
122→        let pos = heat.order.iter().position(|c| c == &target_key)
123→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
124→        Some(pos + 1) // Insert after this position
125→    } else if args.first {
126→        Some(0) // Insert at beginning
127→    } else {
128→        None // Append to end (default)
129→    };
130→
131→    // Construct Coronet
132→    let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
133→
134→    // Create initial Tack and Pace
135→    let tack = jjrg_make_tack(
136→        jjrg_PaceState::Rough,
137→        args.text,
138→        args.silks,
139→        None,
140→    );
141→    let pace = jjrg_Pace {
142→        tacks: vec![tack],
143→    };
144→
145→    // Insert into order at determined position
146→    match insert_position {
147→        Some(pos) => heat.order.insert(pos, coronet_str.clone()),
148→        None => heat.order.push(coronet_str.clone()),
149→    }
150→    heat.paces.insert(coronet_str.clone(), pace);

